361→    companion object {
362→        private val commandAliases = mapOf(
363→            "servers" to "query-servers",
364→            "notifications" to "send-notifications",
365→            "admin-summary" to "send-admin-summary",
366→            "user-mappings" to "manage-user-mappings",
