 3→import com.secman.cli.config.ConfigLoader
 4→import com.secman.crowdstrike.dto.FalconConfigDto
 5→import org.slf4j.LoggerFactory
 6→
 7→/**
 8→ * Config command for CrowdStrike credentials
 9→ *
10→ * Usage (future with Picocli):
11→ *   secman config [options]
12→ *
13→ * For now, this is a simple class for testing the CLI module structure.
14→ *
15→ * Related to: Feature 023-create-in-the
16→ * Task: T051
17→ */
18→class ConfigCommand {
19→    private val log = LoggerFactory.getLogger(ConfigCommand::class.java)
20→    private val configLoader = ConfigLoader()
21→
22→    var clientId: String? = null
23→    var clientSecret: String? = null
24→    var baseUrl: String = "https://api.crowdstrike.com"
25→    var show: Boolean = false
26→    var format: String = "yaml"
27→
28→    fun execute(): Int {
29→        return try {
30→            when {
31→                show -> showConfig()
32→                clientId != null && clientSecret != null -> saveConfig()
33→                else -> {
34→                    System.err.println("Error: Either provide --client-id and --client-secret to save, or use --show to view")
35→                    1
36→                }
37→            }
38→        } catch (e: IllegalArgumentException) {
39→            System.err.println("Error: ${e.message}")
40→            1
41→        } catch (e: Exception) {
42→            System.err.println("Error: ${e.message}")
43→            e.printStackTrace()
44→            1
45→        }
46→    }
47→
48→    private fun showConfig(): Int {
49→        return try {
50→            val config = configLoader.loadConfig()
51→            System.out.println("CrowdStrike Configuration:")
52→            System.out.println("  Client ID: ${config.clientId}")
53→            System.out.println("  Client Secret: ${maskSecret(config.clientSecret)}")
54→            System.out.println("  Base URL: ${config.baseUrl}")
55→            0
56→        } catch (e: Exception) {
57→            System.err.println("Error: No configuration found")
58→            1
59→        }
60→    }
61→
62→    private fun saveConfig(): Int {
63→        try {
64→            val config = FalconConfigDto(
65→                clientId = clientId!!,
66→                clientSecret = clientSecret!!,
67→                baseUrl = baseUrl
68→            )
69→
70→            val filename = if (format == "conf") "crowdstrike.conf" else "crowdstrike.yaml"
71→            configLoader.saveConfig(config, filename)
72→
73→            System.out.println("Configuration saved successfully")
74→            return 0
75→        } catch (e: Exception) {
76→            System.err.println("Error: Failed to save configuration: ${e.message}")
77→            return 1
78→        }
79→    }
80→
81→    fun maskSecret(secret: String): String {
82→        return if (secret.length <= 4) {
83→            "*".repeat(secret.length)
84→        } else {
85→            secret.take(2) + "*".repeat(secret.length - 4) + secret.takeLast(2)
86→        }
87→    }
88→}
