342→    private fun showCommandHelp(command: String): Int {
343→        // Resolve aliases for common variations
344→        val resolvedCommand = commandAliases[command] ?: command
345→        val helpText = commandHelpTexts[resolvedCommand]
346→        if (helpText == null) {
347→            System.err.println("ERROR: Unknown command: '$command'")
348→            System.err.println()
349→            System.err.println("Available commands:")
350→            commandHelpTexts.keys.sorted().forEach { cmd ->
351→                System.err.println("  $cmd")
352→            }
353→            System.err.println()
354→            System.err.println("Run 'secman help' for an overview.")
355→            return 1
356→        }
357→        println(helpText)
358→        return 0
359→    }
